import express from 'express';
import { isAuth, isSeller } from '../middlewares/isAuth.js';
import { addRestauraunt, fetchMyRestaurant, updateRestaurant, updateStatusRestaurant } from '../controllers/restaurant.js';
import uploadFile from '../middlewares/multer.js';
const router = express.Router();
router.post("/new", isAuth, isSeller, uploadFile, addRestauraunt);
router.get("/my", isAuth, isSeller, fetchMyRestaurant);
router.get("/status", isAuth, isSeller, updateStatusRestaurant);
router.get("/edit", isAuth, isSeller, updateRestaurant);
export default router;
